import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import ProductSkeleton from '../components/ProductSkeleton';
import { toast } from 'react-hot-toast';
import AdBanner from '../components/AdBanner';

function Home({ addToCart, API_URL }) {
  const [products, setProducts] = useState([]);
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('default');
  const [error, setError] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetchProducts();
    const userData = localStorage.getItem('user');
    if (userData) {
      setUser(JSON.parse(userData));
    }
  }, []);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await axios.get(`${API_URL}/api/products`);
      console.log('Products received:', response.data);
      
      if (response.data && Array.isArray(response.data)) {
        setProducts(response.data);
        setFilteredProducts(response.data);
      } else {
        setProducts([]);
        setFilteredProducts([]);
        setError('Invalid data format received');
      }
    } catch (error) {
      console.error('Error fetching products:', error);
      setError(error.message);
      setProducts([]);
      setFilteredProducts([]);
    } finally {
      setLoading(false);
    }
  };

  const categories = ['All', ...new Set(products.map(p => p.category))];

  const getCategoryCount = (category) => {
    if (category === 'All') return products.length;
    return products.filter(p => p.category === category).length;
  };

  useEffect(() => {
    let result = [...products];
    
    if (selectedCategory !== 'All') {
      result = result.filter(p => p.category === selectedCategory);
    }
    
    if (searchTerm) {
      result = result.filter(p => 
        p.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.description?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    
    if (sortBy === 'price_low') {
      result.sort((a, b) => a.price - b.price);
    } else if (sortBy === 'price_high') {
      result.sort((a, b) => b.price - a.price);
    }
    
    setFilteredProducts(result);
  }, [selectedCategory, searchTerm, sortBy, products]);

  const handleAddToCart = (product) => {
    if (!user) {
      toast.error('Please login first to add items to cart!');
      setTimeout(() => {
        window.location.href = '/login';
      }, 1500);
      return;
    }
    
    if (product.stock === 0) {
      toast.error('Out of stock!');
      return;
    }
    
    addToCart(product);
  };

  const handleBuyNow = (product) => {
    if (!user) {
      toast.error('Please login first to buy products!');
      setTimeout(() => {
        window.location.href = '/login';
      }, 1500);
      return;
    }
    
    if (product.stock === 0) {
      toast.error('Out of stock! Cannot buy.');
      return;
    }
    
    addToCart(product);
    setTimeout(() => {
      window.location.href = '/cart';
    }, 500);
  };

  // Get top 6 products for hot deals (vertical grid)
  const hotDealsProducts = products.filter(p => p.rating >= 4.0).slice(0, 6);

  if (loading) {
    return (
      <div className="products-grid">
        {[1,2,3,4,5,6].map(n => <ProductSkeleton key={n} />)}
      </div>
    );
  }

  if (error) {
    return (
      <div className="no-results">
        <h3>Error loading products</h3>
        <p>{error}</p>
        <p style={{ fontSize: '14px', color: '#666' }}>
          Make sure backend is running on {API_URL}
        </p>
        <button onClick={fetchProducts}>Try Again</button>
      </div>
    );
  }

  if (products.length === 0) {
    return (
      <div>
        <div className="hero">
          <h1>Welcome to ShopEase</h1>
          <p>Discover amazing products at best prices!</p>
        </div>
        <div className="no-results">
          <h3>No products found in database</h3>
          <button onClick={fetchProducts}>Refresh Products</button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="hero">
        <h1>Welcome to ShopEase</h1>
        <p>Discover {products.length} amazing products at best prices!</p>
        <div className="hero-stats">
          <span>📦 {products.length}+ Products</span>
          <span>⭐ 4.5+ Rating</span>
          <span>🚚 Free Shipping</span>
        </div>
      </div>

      <AdBanner products={products} />

      {/* Hot Deals Section - VERTICAL GRID */}
      {hotDealsProducts.length > 0 && (
        <div className="hot-deals-section">
          <h2>🔥 Hot Deals 🔥</h2>
          <p className="section-subtitle">Limited time offers on trending products!</p>
          <div className="hot-deals-grid">
            {hotDealsProducts.map(product => (
              <div key={product.id} className="hot-deal-card">
                <div className="hot-deal-badge">
                  <span className="discount-tag">-{Math.floor(Math.random() * 30 + 10)}%</span>
                  <span className="hot-tag">HOT</span>
                </div>
                <img 
                  src={product.image_url || 'https://via.placeholder.com/300?text=Product'} 
                  alt={product.name}
                  onError={(e) => { e.target.src = 'https://via.placeholder.com/300?text=Product'; }}
                />
                <div className="hot-deal-info">
                  <h3>{product.name}</h3>
                  <p className="category">{product.category || 'General'}</p>
                  <div className="rating">⭐ {product.rating || 4.5}</div>
                  <div className="price-section">
                    <span className="current-price">${product.price}</span>
                    <span className="old-price">${(product.price * 1.3).toFixed(2)}</span>
                  </div>
                  <div className="stock-info">
                    {product.stock > 0 ? `✅ ${product.stock} left` : '❌ Out of stock'}
                  </div>
                  <div className="hot-deal-buttons">
                    <button 
                      className="add-to-cart-btn"
                      onClick={() => handleAddToCart(product)}
                      disabled={product.stock === 0}
                    >
                      {product.stock === 0 ? 'Out of Stock' : '🛒 Add to Cart'}
                    </button>
                    <button 
                      className="buy-now-btn"
                      onClick={() => handleBuyNow(product)}
                      disabled={product.stock === 0}
                    >
                      ⚡ Buy Now
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="filter-bar">
        <div className="search-box">
          <input 
            type="text" 
            placeholder="🔍 Search products..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        
        <div className="sort-box">
          <select value={sortBy} onChange={(e) => setSortBy(e.target.value)}>
            <option value="default">Sort by: Default</option>
            <option value="price_low">Price: Low to High</option>
            <option value="price_high">Price: High to Low</option>
          </select>
        </div>
      </div>

      <div className="category-tabs">
        {categories.map(cat => (
          <button 
            key={cat}
            className={`category-btn ${selectedCategory === cat ? 'active' : ''}`}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat} <span className="category-count">({getCategoryCount(cat)})</span>
          </button>
        ))}
      </div>

      <div className="results-count">
        Showing {filteredProducts.length} of {products.length} products
      </div>

      <div className="products-grid">
        {filteredProducts.map(product => (
          <div key={product.id} className="product-card">
            <div className="product-badge">
              {product.stock < 10 && product.stock > 0 && <span className="badge low-stock">🔥 Low Stock</span>}
              {product.rating >= 4.5 && <span className="badge bestseller">⭐ Bestseller</span>}
              {product.stock === 0 && <span className="badge out-of-stock">❌ Out of Stock</span>}
            </div>
            <img 
              src={product.image_url || 'https://via.placeholder.com/300?text=Product'} 
              alt={product.name}
              onError={(e) => { e.target.src = 'https://via.placeholder.com/300?text=Product'; }}
            />
            <div className="product-info">
              <h3>{product.name}</h3>
              <p className="category">{product.category || 'General'}</p>
              <p className="description">{product.description?.substring(0, 60)}...</p>
              <div className="rating">
                {'⭐'.repeat(Math.floor(product.rating || 4))} {product.rating || 4}
              </div>
              <div className="price-cart">
                <div>
                  <span className="price">${product.price}</span>
                </div>
                <Link to={`/product/${product.id}`} className="view-details-btn">View Details</Link>
              </div>
              <div className="product-buttons">
                <button 
                  className="add-to-cart-btn-home"
                  onClick={() => handleAddToCart(product)}
                  disabled={product.stock === 0}
                  style={product.stock === 0 ? { background: '#ccc', cursor: 'not-allowed' } : {}}
                >
                  {product.stock === 0 ? '❌ Out of Stock' : (!user ? '🔒 Login to Add' : '🛒 Add to Cart')}
                </button>
                <button 
                  className="buy-now-btn-home"
                  onClick={() => handleBuyNow(product)}
                  disabled={product.stock === 0}
                  style={product.stock === 0 ? { background: '#ccc', cursor: 'not-allowed' } : {}}
                >
                  {product.stock === 0 ? 'Sold Out' : '⚡ Buy Now'}
                </button>
              </div>
              <div className="stock-info">
                {product.stock > 0 ? `✅ In Stock: ${product.stock} items` : '❌ Currently Unavailable'}
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredProducts.length === 0 && (
        <div className="no-results">
          <h3>No products found</h3>
          <p>Try changing your search or filter criteria</p>
        </div>
      )}
    </div>
  );
}

export default Home;
